public class Product {
    int id;
    String name;
    double price;
    String manufacturer;
    String type;

    @Override
    public String toString() {
        return "Product{" +
                "id=" + id +
                ", name='" + name + '\'' +
                ", price=" + price +
                ", manufacturer='" + manufacturer + '\'' +
                ", type='" + type + '\'' +
                '}';
    }
}

public class ProductRepository extends CrudRepository<Product, Integer> {

    @Autowired
    JdbcTemplate template;

    public List<Product> findByName(String name) {
        List<Product> products = new ArrayList<>();

        template.query("SELECT * FROM PRODUCTS WHERE NAME LIKE %?%",
                new Object[]{name + '%'}, (rs, rowNum)->{
                    Product product = new Product();
                    product.id= rs.getInt("ID");
                    product.name = rs.getString("NAME");
                    product.price = rs.getDouble("PRICE");
                    product.manufacturer = rs.getString("MANUFACTURER");
                    product.type = rs.getString("TYPE");

                    products.add(product);
                });

        return products;
    }
}


